<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;permissionFilterApplied&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
